  ('country', 'DK', '[{"code":"da","type":"official","coverage":1},{"code":"en","type":"widely_spoken","coverage":0.9}]'::jsonb, 'Denmark should score Danish as the national language while giving very high English credit because VisitDenmark explicitly says it is easy to get around in English and that over 90% of Danes speak it fluently.', 'official_danish_with_very_high_english_override', '[{"kind":"official_tourism","title":"VisitDenmark: Language","url":"https://www.visitdenmark.com/faq/language","note":"VisitDenmark says the national language is Danish."},{"kind":"official_tourism","title":"VisitDenmark: Speaking English in Denmark","url":"https://www.visitdenmark.com/faq/speaking-english-in-denmark","note":"VisitDenmark says Danes have a very good level of English and that it is easy to get around the country even if you do not speak Danish."},{"kind":"official_tourism","title":"VisitDenmark: Denmark basics for event planners","url":"https://www.visitdenmark.com/business-events/contacts/denmark-basics","note":"VisitDenmark says over 90% of Danes speak English fluently."}]'::jsonb),
